1	// claim-office.ts
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	};
9	
10	const FIRST_INSURANCE_PERCENT = 110;
11	const PROCESSING_FEE = 5;
12	
13	export function processScenario(scenario: any): unknown {
14	  const [{ items }] = scenario.steps;
15	  const itemsBaseTotal = items.reduce(
16	    (total: number, item: { type: string }) => total + BASE_PREMIUMS[item.type],
17	    0,
18	  );
19	  const itemsAfterFirstInsurance = (itemsBaseTotal * FIRST_INSURANCE_PERCENT) / 100;
20	  const premium = itemsAfterFirstInsurance + PROCESSING_FEE;
21	  return { results: [{ premium }] };
22	}
